import React, { useEffect, useState } from "react";
import axios from "axios";

const API_BASE = "http://localhost:8080/api/properties";

function PropertyList() {
  const [properties, setProperties] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    fetchProperties();
  }, []);

  const fetchProperties = async () => {
    try {
      setLoading(true);
      const response = await axios.get(API_BASE);
      const content = response.data?.data?.content || [];
      setProperties(content);
      setFiltered(content);
      setError("");
    } catch (err) {
      setError("Failed to fetch properties");
      setProperties([]);
      setFiltered([]);
    } finally {
      setLoading(false);
    }
  };

  const searchProperties = async (keyword) => {
    setSearch(keyword);

    if (keyword.trim() === "") {
      setFiltered(properties);
      return;
    }

    try {
      const response = await axios.get(`${API_BASE}/search`, {
        params: { keyword },
      });

      setFiltered(response.data?.data?.content || []);
      setError("");
    } catch (err) {
      setError("Search failed");
      setFiltered([]);
    }
  };

  return (
    <div style={{ width: "90%", margin: "0 auto" }}>
      <input
        type="text"
        placeholder="Search by city, type, title..."
        value={search}
        onChange={(e) => searchProperties(e.target.value)}
        style={{
          width: "100%",
          padding: "12px",
          fontSize: "16px",
          marginBottom: "25px",
          borderRadius: "6px",
          border: "1px solid #bbb"
        }}
      />

      <h2 style={{ fontSize: "26px", marginBottom: "20px" }}>All Properties</h2>

      {loading && <p>Loading...</p>}
      {error && <p style={{ color: "red" }}>{error}</p>}

      {filtered.length === 0 && <p>No properties found.</p>}

      <div style={{
        display: "grid",
        gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))",
        gap: "20px"
      }}>
        {filtered.map((p) => (
          <div
            key={p.id}
            style={{
              padding: "20px",
              border: "1px solid #ddd",
              borderRadius: "10px",
              backgroundColor: "#fff",
              boxShadow: "0 3px 10px rgba(0,0,0,0.1)"
            }}
          >
            <h3 style={{ marginBottom: "10px" }}>{p.title}</h3>

            <p><strong>City:</strong> {p.city}</p>
            <p><strong>Price:</strong> ₹{p.price}</p>
            <p><strong>Type:</strong> {p.type}</p>
            <p><strong>Description:</strong> {p.description}</p>
            <p><strong>Location:</strong> {p.location}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default PropertyList;
